var e=[{id:`L2_1`,type:`dialog`,speaker:`TWINTAIL_LEGACY_NULL_NULL`,text:{KOREA:`두고 봐. 이 몸은 언젠가 진짜 인류의 영웅이 돼 보일 테니까. 물론 투자를 해준 당신을 위해서 조금은 협력해 줄게.`,JPN:`見てなさいよ。このナイエル様はいつか本物の人類の英雄になってみせるから。もちろん、投資してくれたあんたのことを思って少しは協力してあげる。`,ENG:`Just wait and see. Because I'm going to be the true hero of humanity one day. Of course, I'll cooperate since you put your trust in me.`,TWN:`等著瞧，總有一天我真正會成為人類的英雄。當然，畢竟你在我身上也投資不少，我多少會回饋一點給你的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_LEGACY_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`TWINTAIL_LEGACY_NULL_NULL`,text:{KOREA:`철들었다고?`,JPN:`やっと分別がつくようになったですって？`,ENG:`I've matured?`,TWN:`你說我懂事啦？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_LEGACY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`TWINTAIL_LEGACY_NULL_NULL`,text:{KOREA:`나, 난 원래부터 철들었거든?!`,JPN:`私はもとからこんな感じだったけど！？`,ENG:`I-I've always been mature!!`,TWN:`拜託，我本來就很懂事好嗎！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`TWINTAIL_LEGACY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};